    "Real-Time Market Prices": { "en": "Real-Time Market Prices", "ta": "நிகழ்நேர சந்தை விலைகள்", "hi": "वास्तविक समय बाजार भाव", "te": "నిజ-సమయ మార్కెట్ ధరలు", "kn": "ನೈಜ-ಸಮಯದ ಮಾರುಕಟ್ಟೆ ಬೆಲೆಗಳು" },
    "Disease Detection": { "en": "Disease Detection", "ta": "நோய் கண்டறிதல்", "hi": "रोग पहचान", "te": "వ్యాதி ಗುರುತಿಸುವಿಕೆ", "kn": "ರೋಗ ಪತ್ತೆ" },
    "Government Schemes": { "en": "Government Schemes", "ta": "அரசு திட்டங்கள்", "hi": "सरकारी योजनाएं", "te": "ప్రభుత్వ పథకాలు", "kn": "ಸರ್ಕಾರಿ ಯೋಜನೆಗಳು" },
    "Direct Buyer Connection": { "en": "Direct Buyer Connection", "ta": "நேரடி கொள்முதல் இணைப்பு", "hi": "प्रत्यक्ष खरीदार कनेक्शन", "te": "నేరుగా కొనుగోలుదారు కనెక్షన్", "kn": "ನೇರ ಖರೀದಿದಾರ ಸಂಪರ್ಕ" },
