    "Annual Crops": { "en": "Annual Crops", "ta": "ஆண்டு பயிர்கள்", "hi": "वार्षिक फसलें", "te": "వార్షిక పంటలు", "kn": "ವಾರ್ಷಿಕ ಬೆಳೆಗಳು" },
    "Select Soil Type": { "en": "Select Soil Type", "ta": "மண் வகையைத் தேர்ந்தெடுக்கவும்", "hi": "मिट्टी का प्रकार चुनें", "te": "నేల రకాన్ని ఎంచుకోండి", "kn": "ಮಣ್ಣಿನ ಪ್ರಕಾರವನ್ನು ಆಯ್ಕೆಮಾಡಿ" },
