    "crops found": { "en": "crops found", "ta": "பயிர்கள் கண்டறியப்பட்டன", "hi": "फसलें मिलीं", "te": "పంటలు కనుగొనబడ్డాయి", "kn": "ಬೆಳೆಗಳು ಕಂಡುಬಂದಿವೆ" },
    "No crops found for selected filters": { "en": "No crops found for selected filters", "ta": "தேர்ந்தெடுக்கப்பட்ட வடிப்பான்களுக்கு பயிர்கள் எதுவும் இல்லை", "hi": "चयनित फिल्टर के लिए कोई फसल नहीं मिली", "te": "ఎంచుకున్న ఫిల్టర్ల కోసం పంటలు కనుగొనబడలేదు", "kn": "ಆಯ್ದ ಫಿಲ್ಟರ್‌ಗಳಿಗಾಗಿ ಯಾವುದೇ ಬೆಳೆಗಳು ಕಂಡುಬಂದಿಲ್ಲ" },
    "Try selecting different season or soil type": { "en": "Try selecting different season or soil type", "ta": "வேறு பருவம் அல்லது மண் வகையைத் தேர்ந்தெடுத்து முயற்சிக்கவும்", "hi": "अलग सीजन या मिट्टी का प्रकार चुनने का प्रयास करें", "te": "విభిన్న సీజన్ లేదా నేల రకాన్ని ఎంచుకోవడానికి ప్రయత్నించండి", "kn": "ಬೇರೆ ಋತು ಅಥವಾ ಮಣ್ಣಿನ ಪ್ರಕಾರವನ್ನು ಆಯ್ಕೆ ಮಾಡಲು ಪ್ರಯತ್ನಿಸಿ" },
